  assert restrictions[..0] == [];

  // Loop 2: Apply each restriction
  i := 0;
  while i < |restrictions|
    invariant 0 <= i <= |restrictions|
    invariant forall j | 0 <= j < n :: ans[j] == EffectiveCap(j, h, restrictions[..i])
